import { API_BASE_URL, getApiHeaders, getApiHeadersPost } from '../config/constants';

export const getEmployeeList = async (params = {}) => {
  try {
    // Validate and build query parameters
    const queryParams = new URLSearchParams();
    
    // Add parameters if they exist and are not empty
    if (params.type !== undefined && params.type !== null) {
      queryParams.append('type', params.type.toString());
    }
    if (params.page !== undefined && params.page !== null) {
      queryParams.append('page', params.page.toString());
    }
    if (params.pageSize !== undefined && params.pageSize !== null) {
      queryParams.append('pageSize', params.pageSize.toString());
    }
    if (params.search && params.search.trim()) {
      queryParams.append('search', params.search.trim());
    }
    if (params.sort && params.sort.trim()) {
      queryParams.append('sort', params.sort.trim());
    }
    if (params.order && params.order.trim()) {
      queryParams.append('order', params.order.trim());
    }
    if (params.position_id && params.position_id.trim() && params.position_id !== 'all') {
      queryParams.append('position_id', params.position_id.trim());
    }
    if (params.record_status && params.record_status.trim() && params.record_status !== 'all') {
      queryParams.append('record_status', params.record_status.trim());
    }

    // Prepare headers with authorization
    const headers = getApiHeaders();

    // Make API call using fetch
    const response = await fetch(`${API_BASE_URL}/employee/list?${queryParams.toString()}`, {
      method: 'GET',
      headers: headers,
    });

    // Handle response
    if (!response.ok) {
      // Try to get error message from response
      let errorMessage = 'Failed to fetch employee data';
      try {
        const errorData = await response.json();
        errorMessage = errorData.message || errorData.error || errorMessage;
      } catch (e) {
        // If response is not JSON, use status text
        errorMessage = response.statusText || errorMessage;
      }
      
      return {
        success: false,
        error: errorMessage,
        status: response.status,
      };
    }

    // Parse successful response
    const data = await response.json();
    
    return {
      success: true,
      data: data,
    };
  } catch (error) {
    // Handle network errors
    if (error.name === 'TypeError' && error.message.includes('fetch')) {
      return {
        success: false,
        error: 'Network error. Please check if the server is running.',
      };
    } else {
      return {
        success: false,
        error: 'An unexpected error occurred while fetching employee data',
      };
    }
  }
};

export const viewEmployee = async (id) => {
  try {
    const headers = getApiHeaders();
    const response = await fetch(`${API_BASE_URL}/employee/view?id=${id}`, {
      method: 'GET',
      headers: headers,
    });

    if (!response.ok) {
      let errorMessage = 'Failed to fetch employee details';
      try {
        const errorData = await response.json();
        errorMessage = errorData.message || errorData.error || errorMessage;
      } catch (e) {
        errorMessage = response.statusText || errorMessage;
      }
      
      return {
        success: false,
        error: errorMessage,
        status: response.status,
      };
    }

    const data = await response.json();
    
    return {
      success: true,
      data: data.data,
    };
  } catch (error) {
    return {
      success: false,
      error: 'An unexpected error occurred while fetching employee details',
    };
  }
};

export const createEmployee = async (itemData) => {
  try {
    // Create URL-encoded form data like login system
    const formData = new URLSearchParams();
    Object.keys(itemData).forEach(key => {
      formData.append(key, itemData[key]);
    });

    const response = await fetch(`${API_BASE_URL}/employee/register`, {
      method: 'POST',
      headers: getApiHeadersPost(),
      body: formData,
    });

    if (!response.ok) {
      let errorMessage = 'Failed to create employee record';
      try {
        const errorData = await response.json();
        errorMessage = errorData; // errorMessage || errorData.message || errorData.error;
      } catch (e) {
        errorMessage = response.statusText || errorMessage;
      }
      
      return {
        success: false,
        error: errorMessage,
        status: response.status,
      };
    }

    const data = await response.json();
    
    return {
      success: true,
      data: data,
    };
  } catch (error) {
    if (error.name === 'TypeError' && error.message.includes('fetch')) {
      return {
        success: false,
        error: 'Network error. Please check if the server is running.',
      };
    } else {
      return {
        success: false,
        error: 'An unexpected error occurred while creating employee record',
      };
    }
  }
};

